import { execSync } from "child_process"; import fs from "fs";
const repo=process.env.GH_REPO, tok=process.env.GH_TOKEN;
const DEV="https://dev.avesa.lt";
const WPU=(process.env.WP_USER||"").trim();
const WPP=(process.env.WP_APP_PASS||"").replace(/\s+/g,"");
const BP_DATA = Buffer.from("", "base64");
const BN_DATA = Buffer.from("", "base64");
const NA_HTML = Buffer.from("", "base64").toString("utf8");
function putFile(name,str){ try{ const url='https://api.github.com/repos/'+repo+'/contents/screenshots/'+name; let sha=''; try{ sha=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||''; }catch(e){} const body={message:'ed',branch:'main',content:Buffer.from(str,'utf8').toString('base64')}; if(sha) body.sha=sha; fs.writeFileSync('/tmp/pf.json',JSON.stringify(body)); execSync('curl -s -o /dev/null -X PUT -H "Authorization: Bearer '+tok+'" -H "Accept: application/vnd.github+json" -d @/tmp/pf.json "'+url+'"',{encoding:'utf8'}); }catch(e){} }
function api(path,method,obj){ let cmd='curl -sk -u "$WPU:$WPP" -H "Content-Type: application/json" '; if(method) cmd+='-X '+method+' '; if(obj){ fs.writeFileSync('/tmp/body.json', JSON.stringify(obj)); cmd+='-d @/tmp/body.json '; } cmd+='"'+DEV+path+'"'; try{ return execSync(cmd,{encoding:'utf8',maxBuffer:20000000,timeout:60000,env:{...process.env,WPU,WPP}}); }catch(e){ return 'EXC'; }}
let out='';
// 1. Įkeliu 2 banerius
for(const [name, data] of [['banner-pasiulymai.webp', BP_DATA], ['banner-naujam-augintiniui.webp', BN_DATA]]){
  const tmp = '/tmp/upl_' + name;
  fs.writeFileSync(tmp, data);
  try{
    const r = execSync('curl -sk -u "$WPU:$WPP" -F "file=@'+tmp+'" "'+DEV+'/wp-json/wp/v2/media"',
      {encoding:'utf8', maxBuffer:50000000, timeout:60000, env:{...process.env, WPU, WPP}});
    let j; try{ j=JSON.parse(r); }catch(e){ j={parse:'err'}; }
    out += name+': '+(j.id?('id='+j.id+' url='+j.source_url):('ERR='+r.slice(0,150)))+'\n';
  }catch(e){ out += name+' EXC: '+String(e).slice(0,100)+'\n'; }
}
// 2. Sukuriu /naujas-augintinis/ page
const rp = api('/wp-json/wp/v2/pages','POST',{slug:'naujas-augintinis', title:'Naujam augintiniui', content:NA_HTML, status:'publish'});
try{ const j=JSON.parse(rp); out += 'naujas-augintinis: id='+(j.id||'FAIL')+'\n'; }catch(e){ out += 'landing_err\n'; }
putFile('deploy_e2.txt', out);
